import React, { useEffect, useMemo, useState } from "react";
import "./styles/global.css";

const products = [
  { id: 1, name: "Floral Silk Dress", brand: "Sabyasachi", cat: "Women", price: 4999, oldPrice: 7999, emoji: "👗", rating: 4.8, reviews: 324, tag: "SALE", desc: "Exquisite floral silk dress with intricate embroidery. Perfect for festive occasions.", inStock: true },
  { id: 2, name: "Classic Oxford Shirt", brand: "Arrow", cat: "Men", price: 1499, oldPrice: 2499, emoji: "👔", rating: 4.5, reviews: 189, tag: "NEW", desc: "Premium cotton Oxford shirt for the modern gentleman. Tailored fit.", inStock: true },
  { id: 3, name: "Pro Max Smartphone", brand: "Apple", cat: "Electronics", price: 89999, oldPrice: 99999, emoji: "📱", rating: 4.9, reviews: 1204, tag: "HOT", desc: "The latest flagship smartphone with breakthrough camera system.", inStock: true },
  { id: 4, name: "Luxury Lip Kit", brand: "MAC", cat: "Beauty", price: 2199, oldPrice: 2999, emoji: "💄", rating: 4.7, reviews: 567, tag: "SALE", desc: "Matte finish luxury lip kit with 6 curated shades for every occasion.", inStock: true },
  { id: 5, name: "Artisan Coffee Table", brand: "Urban Ladder", cat: "Home", price: 12999, oldPrice: 18999, emoji: "🛋️", rating: 4.6, reviews: 98, tag: "SALE", desc: "Handcrafted sheesham wood coffee table with hairpin legs. Timeless design.", inStock: true },
  { id: 6, name: "Running Pro Elite", brand: "Nike", cat: "Sports", price: 7499, oldPrice: 9999, emoji: "👟", rating: 4.8, reviews: 445, tag: "HOT", desc: "Professional running shoes with React foam cushioning for peak performance.", inStock: true },
  { id: 7, name: "Wireless Noise Canceling", brand: "Sony", cat: "Electronics", price: 24999, oldPrice: 34999, emoji: "🎧", rating: 4.9, reviews: 892, tag: "SALE", desc: "Industry-leading noise cancellation with 30-hour battery life.", inStock: true },
  { id: 8, name: "Diamond Solitaire Ring", brand: "Tanishq", cat: "Jewelry", price: 45000, oldPrice: 52000, emoji: "💍", rating: 4.9, reviews: 156, tag: "LUXURY", desc: "18K gold ring with certified VS1 diamond. Certificate of authenticity included.", inStock: true },
  { id: 9, name: "Cashmere Turtleneck", brand: "Zara", cat: "Women", price: 3499, oldPrice: 4999, emoji: "🧶", rating: 4.6, reviews: 234, tag: "NEW", desc: "Pure cashmere turtleneck sweater in winter-ready palette.", inStock: true },
  { id: 10, name: "Chino Slim Fit", brand: "H&M", cat: "Men", price: 1999, oldPrice: 2999, emoji: "👖", rating: 4.4, reviews: 167, tag: null, desc: "Slim-fit stretch chinos perfect for smart-casual occasions.", inStock: true },
  { id: 11, name: "4K Smart TV 55\"", brand: "Samsung", cat: "Electronics", price: 54999, oldPrice: 74999, emoji: "📺", rating: 4.8, reviews: 678, tag: "SALE", desc: "Crystal clear 4K resolution with built-in smart TV and voice assistant.", inStock: true },
  { id: 12, name: "Serum Set Collection", brand: "The Ordinary", cat: "Beauty", price: 1899, oldPrice: 2599, emoji: "✨", rating: 4.7, reviews: 389, tag: "NEW", desc: "Scientifically formulated serum set targeting dark spots and aging.", inStock: true },
  { id: 13, name: "Designer Tote Bag", brand: "Hidesign", cat: "Women", price: 8999, oldPrice: 12999, emoji: "👜", rating: 4.8, reviews: 201, tag: "HOT", desc: "Genuine full-grain leather tote. Spacious, structured, sophisticated.", inStock: true },
  { id: 14, name: "Chronograph Watch", brand: "Titan", cat: "Men", price: 15999, oldPrice: 21999, emoji: "⌚", rating: 4.7, reviews: 312, tag: "LUXURY", desc: "Swiss movement chronograph with sapphire crystal glass and leather strap.", inStock: true },
  { id: 15, name: "Yoga Mat Pro", brand: "Manduka", cat: "Sports", price: 3999, oldPrice: 5499, emoji: "🧘", rating: 4.6, reviews: 445, tag: null, desc: "6mm thick eco-friendly yoga mat with superior grip and cushioning.", inStock: true },
  { id: 16, name: "Best Seller Novel", brand: "Penguin", cat: "Books", price: 499, oldPrice: 699, emoji: "📚", rating: 4.9, reviews: 1567, tag: "HOT", desc: "The acclaimed novel that topped charts worldwide. A masterpiece of modern fiction.", inStock: true },
  { id: 17, name: "Gold Pendant Necklace", brand: "Malabar Gold", cat: "Jewelry", price: 18500, oldPrice: 22000, emoji: "📿", rating: 4.8, reviews: 88, tag: null, desc: "22K hallmarked gold pendant with traditional motif. Timeless heirloom.", inStock: true },
  { id: 18, name: "Air Purifier Ultra", brand: "Dyson", cat: "Home", price: 34999, oldPrice: 44999, emoji: "💨", rating: 4.7, reviews: 234, tag: "SALE", desc: "HEPA + activated carbon filtration. Removes 99.97% of pollutants.", inStock: true },
];

const sampleOrders = [
  { id: '#LUXE-7841', date: 'May 18, 2025', items: 'Nike Running Shoes, Sony WH-1000XM5', amount: '₹32,498', status: 'Delivered' },
  { id: '#LUXE-7623', date: 'May 10, 2025', items: 'Sabyasachi Dress', amount: '₹4,999', status: 'Delivered' },
  { id: '#LUXE-7490', date: 'Apr 28, 2025', items: 'Samsung 4K TV', amount: '₹54,999', status: 'Processing' },
  { id: '#LUXE-7301', date: 'Apr 15, 2025', items: 'Dyson Air Purifier', amount: '₹34,999', status: 'Shipped' },
];

export default function App() {
  const [page, setPage] = useState("home");
  const [cart, setCart] = useState([]);
  const [wishlist, setWishlist] = useState([]);
  const [cartDiscount, setCartDiscount] = useState(0);
  const [currentProduct, setCurrentProduct] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState({ name: 'John Doe', email: 'john@luxe.com' });
  const [catFilter, setCatFilter] = useState('all');
  const [priceMin, setPriceMin] = useState('');
  const [priceMax, setPriceMax] = useState('');
  const [ratingFilter, setRatingFilter] = useState('0');
  const [filterSale, setFilterSale] = useState(false);
  const [filterInStock, setFilterInStock] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [sortOption, setSortOption] = useState('featured');
  const [dashboardTab, setDashboardTab] = useState('overview');
  const [detailTab, setDetailTab] = useState('tab-desc');
  const [toast, setToast] = useState({ visible: false, message: '' });
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [page]);

  useEffect(() => {
    if (!toast.visible) return;
    const timer = window.setTimeout(() => setToast({ visible: false, message: '' }), 3000);
    return () => window.clearTimeout(timer);
  }, [toast.visible]);

  const filteredProducts = useMemo(() => {
    const minP = parseFloat(priceMin) || 0;
    const maxP = priceMax.trim() === '' ? Infinity : parseFloat(priceMax);
    const minR = parseFloat(ratingFilter) || 0;
    const query = searchQuery.toLowerCase().trim();

    const list = products.filter(p => {
      if (catFilter !== 'all' && p.cat !== catFilter) return false;
      if (p.price < minP || p.price > maxP) return false;
      if (p.rating < minR) return false;
      if (filterSale && !p.oldPrice) return false;
      if (filterInStock && !p.inStock) return false;
      if (query && !p.name.toLowerCase().includes(query) && !p.brand.toLowerCase().includes(query)) return false;
      return true;
    });

    if (sortOption === 'price-low') return list.sort((a, b) => a.price - b.price);
    if (sortOption === 'price-high') return list.sort((a, b) => b.price - a.price);
    if (sortOption === 'rating') return list.sort((a, b) => b.rating - a.rating);
    return list;
  }, [catFilter, filterInStock, filterSale, priceMax, priceMin, ratingFilter, searchQuery, sortOption]);

  const cartQuantity = cart.reduce((sum, item) => sum + item.qty, 0);
  const wishlistCount = wishlist.length;
  const subtotal = cart.reduce((sum, item) => sum + item.price * item.qty, 0);
  const total = subtotal - cartDiscount;

  const pageClass = id => page === id ? 'page active' : 'page';

  function showPage(id) {
    if (id === 'dashboard' && !isLoggedIn) {
      setPage('login');
      setMobileOpen(false);
      return;
    }
    setPage(id);
    setMobileOpen(false);
  }

  function showToast(message) {
    setToast({ visible: true, message });
  }

  function doLogin() {
    setIsLoggedIn(true);
    setCurrentUser({ name: 'John Doe', email: 'john@luxe.com' });
    showToast('✓ Welcome back, John!');
    setPage('home');
  }

  function doRegister() {
    setIsLoggedIn(true);
    setCurrentUser({ name: 'New User', email: 'newuser@luxe.com' });
    showToast('🎉 Account created! Welcome to LUXE!');
    setPage('home');
  }

  function doLogout() {
    setIsLoggedIn(false);
    showToast('👋 Signed out successfully');
    setPage('home');
  }

  function addToCart(id) {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (existing) return prev.map(item => item.id === id ? { ...item, qty: item.qty + 1 } : item);
      const product = products.find(p => p.id === id);
      return product ? [...prev, { ...product, qty: 1 }] : prev;
    });
    const product = products.find(p => p.id === id);
    if (product) showToast(`✓ ${product.name} added to cart!`);
  }

  function updateQty(id, delta) {
    setCart(prev => {
      const next = prev
        .map(item => item.id === id ? { ...item, qty: item.qty + delta } : item)
        .filter(item => item.qty > 0);
      return next;
    });
  }

  function removeFromCart(id) {
    setCart(prev => prev.filter(item => item.id !== id));
    showToast('Item removed from cart');
  }

  function applyCoupon() {
    const code = couponCode.trim().toUpperCase();
    if (code === 'LUXE10') { setCartDiscount(500); showToast('✓ Coupon LUXE10 applied! ₹500 off'); }
    else if (code === 'FIRST15') { setCartDiscount(750); showToast('✓ Coupon FIRST15 applied! ₹750 off'); }
    else showToast('❌ Invalid coupon code');
  }

  const [couponCode, setCouponCode] = useState('');

  function toggleWishlist(id) {
    setWishlist(prev => {
      const exists = prev.some(item => item.id === id);
      if (exists) {
        showToast('Removed from wishlist');
        return prev.filter(item => item.id !== id);
      }
      const product = products.find(p => p.id === id);
      if (product) showToast(`♥ ${product.name} added to wishlist!`);
      return product ? [...prev, product] : prev;
    });
  }

  function showProduct(id) {
    const product = products.find(p => p.id === id);
    if (!product) return;
    setCurrentProduct(product);
    setDetailTab('tab-desc');
    setPage('product');
  }

  function addToCartFromDetail() {
    if (currentProduct) addToCart(currentProduct.id);
  }

  function addToWishlistFromDetail() {
    if (currentProduct) toggleWishlist(currentProduct.id);
  }

  function filterAndShowCatalog(category) {
    setCatFilter(category);
    setPage('catalog');
  }

  function resetFilters() {
    setCatFilter('all');
    setRatingFilter('0');
    setPriceMin('');
    setPriceMax('');
    setFilterSale(false);
    setFilterInStock(false);
    setSearchQuery('');
    setSortOption('featured');
  }

  function renderProductCard(product) {
    const inWish = wishlist.some(item => item.id === product.id);
    return (
      <div className="product-card" key={product.id} onClick={() => showProduct(product.id)}>
        <div className="product-img">
          <span>{product.emoji}</span>
          <button
            className="wishlist-btn"
            onClick={e => { e.stopPropagation(); toggleWishlist(product.id); }}
          >
            {inWish ? '❤️' : '🤍'}
          </button>
          {product.tag ? <div className="badge-tag">{product.tag}</div> : null}
        </div>
        <div className="product-info">
          <div className="product-brand">{product.brand}</div>
          <div className="product-name">{product.name}</div>
          <div className="product-stars">
            <span className="stars">{'⭐'.repeat(Math.floor(product.rating))}</span>
            <span className="review-count">({product.reviews})</span>
          </div>
          <div className="product-price-row">
            <div>
              <span className="price">₹{product.price.toLocaleString()}</span>
              {product.oldPrice ? <span className="price-old">₹{product.oldPrice.toLocaleString()}</span> : null}
            </div>
            <button
              className="add-cart-btn"
              onClick={e => { e.stopPropagation(); addToCart(product.id); }}
            >
              + Cart
            </button>
          </div>
        </div>
      </div>
    );
  }

  function placeOrder() {
    if (cart.length === 0) { showToast('❌ Your cart is empty!'); return; }
    setCart([]);
    setCartDiscount(0);
    showPage('success');
  }

  const currentDetail = currentProduct || products[0];
  const detailProduct = currentProduct || currentDetail;
  const detailSizesHidden = ['Electronics', 'Home', 'Books', 'Beauty'].includes(detailProduct.cat);

  return (
    <>
      <div className={pageClass('home')}>
        <nav>
          <div className="nav-logo" onClick={() => showPage('home')}>LUXE</div>
          <ul className="nav-links">
            <li><a onClick={() => showPage('home')}>Home</a></li>
            <li><a onClick={() => showPage('catalog')}>Shop</a></li>
            <li><a onClick={() => showPage('home')}>Collections</a></li>
            <li><a onClick={() => showPage('home')}>About</a></li>
            <li><a onClick={() => showPage('home')}>Contact</a></li>
          </ul>
          <div className="nav-actions">
            <button className="nav-icon-btn" onClick={() => showPage('catalog')} title="Search">🔍</button>
            <button className="nav-icon-btn" onClick={() => showPage('wishlist')} title="Wishlist">
              🤍 <span className="badge" id="wishlist-badge">{wishlistCount}</span>
            </button>
            <button className="nav-icon-btn" onClick={() => showPage('cart')} title="Cart">
              🛒 <span className="badge" id="cart-badge">{cartQuantity}</span>
            </button>
            <button className="btn-nav-login" onClick={() => showPage(isLoggedIn ? 'dashboard' : 'login')}>
              {isLoggedIn ? 'Dashboard' : 'Sign In'}
            </button>
            <button className="hamburger" onClick={() => setMobileOpen(prev => !prev)}>☰</button>
          </div>
        </nav>
        <div className={`mobile-menu${mobileOpen ? ' open' : ''}`} id="mobile-menu">
          <a onClick={() => { showPage('home'); setMobileOpen(false); }}>Home</a>
          <a onClick={() => { showPage('catalog'); setMobileOpen(false); }}>Shop All</a>
          <a onClick={() => { showPage('cart'); setMobileOpen(false); }}>Cart</a>
          <a onClick={() => { showPage('wishlist'); setMobileOpen(false); }}>Wishlist</a>
          <a onClick={() => { showPage('dashboard'); setMobileOpen(false); }}>Dashboard</a>
          <a onClick={() => { showPage('login'); setMobileOpen(false); }}>Sign In</a>
        </div>

        <div className="hero">
          <div className="hero-content">
            <div className="hero-tag">✦ New Collection 2025</div>
            <h1>Elevate Your <span>Personal</span> Style</h1>
            <p>Discover curated luxury fashion, beauty, and lifestyle products. Every piece tells a story of craftsmanship and elegance.</p>
            <div className="hero-btns">
              <button className="btn btn-primary" onClick={() => showPage('catalog')}>Explore Collection</button>
              <button className="btn btn-outline" onClick={() => showPage('catalog')}>View Lookbook</button>
            </div>
            <div className="hero-stats">
              <div className="stat"><div className="stat-num">12K+</div><div className="stat-label">Products</div></div>
              <div className="stat"><div className="stat-num">850+</div><div className="stat-label">Brands</div></div>
              <div className="stat"><div className="stat-num">4.9★</div><div className="stat-label">Rating</div></div>
            </div>
          </div>
          <div className="hero-visual">
            <div className="hero-img-grid">
              <div><div style={{ height: '100%', background: '#1A1A1A', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '8rem' }}>👗</div></div>
              <div><div style={{ height: '100%', background: '#2D2011', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '8rem' }}>👠</div></div>
              <div><div style={{ height: '100%', background: '#2D2011', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '8rem' }}>👜</div></div>
              <div><div style={{ height: '100%', background: '#1A1A1A', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '8rem' }}>⌚</div></div>
            </div>
          </div>
        </div>

        <section className="categories-section">
          <div className="container">
            <div className="section-header">
              <div className="section-tag">✦ Browse By</div>
              <h2 className="section-title">Shop <span>Categories</span></h2>
            </div>
            <div className="categories-grid">
              {[
                { label: "Women's Fashion", icon: '👗', cat: 'Women', count: '2,480 items' },
                { label: "Men's Fashion", icon: '👔', cat: 'Men', count: '1,920 items' },
                { label: 'Electronics', icon: '📱', cat: 'Electronics', count: '3,150 items' },
                { label: 'Beauty', icon: '💄', cat: 'Beauty', count: '1,640 items' },
                { label: 'Home & Living', icon: '🏠', cat: 'Home', count: '2,100 items' },
                { label: 'Sports', icon: '⚽', cat: 'Sports', count: '980 items' },
                { label: 'Books', icon: '📚', cat: 'Books', count: '5,200 items' },
                { label: 'Jewelry', icon: '💍', cat: 'Jewelry', count: '760 items' },
              ].map(cat => (
                <div key={cat.cat} className="category-card" onClick={() => filterAndShowCatalog(cat.cat)}>
                  <div className="cat-icon">{cat.icon}</div>
                  <div className="cat-name">{cat.label}</div>
                  <div className="cat-count">{cat.count}</div>
                </div>
              ))}
            </div>
          </div>
        </section>

        <section>
          <div className="container">
            <div className="section-header">
              <div className="section-tag">✦ Handpicked</div>
              <h2 className="section-title">Featured <span>Products</span></h2>
            </div>
            <div className="products-grid" id="home-featured">
              {products.slice(0, 6).map(renderProductCard)}
            </div>
            <div style={{ textAlign: 'center', marginTop: '2.5rem' }}>
              <button className="btn btn-dark" onClick={() => showPage('catalog')}>View All Products →</button>
            </div>
          </div>
        </section>

        <section className="features-section">
          <div className="container">
            <div className="features-grid">
              {[
                { icon: '🚚', title: 'Free Shipping', desc: 'On orders over ₹999. Express delivery in 2-3 business days worldwide.' },
                { icon: '🔒', title: 'Secure Payments', desc: '256-bit SSL encryption. Your payment info is always protected.' },
                { icon: '↩️', title: 'Easy Returns', desc: '30-day hassle-free returns. No questions asked, full refund.' },
                { icon: '🎖️', title: 'Authentic Products', desc: '100% genuine products verified by our expert team.' },
              ].map(feature => (
                <div key={feature.title} className="feature-item">
                  <div className="feature-icon">{feature.icon}</div>
                  <div className="feature-title">{feature.title}</div>
                  <div className="feature-desc">{feature.desc}</div>
                </div>
              ))}
            </div>
          </div>
        </section>

        <div className="newsletter">
          <div className="newsletter-inner">
            <div className="section-tag">✦ Stay Connected</div>
            <h3 className="section-title">Get Exclusive <span style={{ color: 'var(--gold)' }}>Offers</span></h3>
            <p>Subscribe to get 15% off your first order and early access to new collections.</p>
            <div className="newsletter-form">
              <input type="email" placeholder="Enter your email address" />
              <button onClick={() => showToast('🎉 Subscribed! Check your email.')}>Subscribe</button>
            </div>
          </div>
        </div>

        <footer>
          <div className="footer-grid">
            <div className="footer-brand">
              <div className="logo">LUXE</div>
              <p>Your destination for premium fashion, beauty, and lifestyle. Curated with passion, delivered with care.</p>
            </div>
            <div className="footer-col">
              <h4>Shop</h4>
              <ul>
                <li><a onClick={() => showPage('catalog')}>New Arrivals</a></li>
                <li><a onClick={() => showPage('catalog')}>Best Sellers</a></li>
                <li><a onClick={() => showPage('catalog')}>Sale</a></li>
                <li><a onClick={() => showPage('catalog')}>Collections</a></li>
              </ul>
            </div>
            <div className="footer-col">
              <h4>Support</h4>
              <ul>
                <li><a>Track Order</a></li>
                <li><a>Returns & Refunds</a></li>
                <li><a>Size Guide</a></li>
                <li><a>Contact Us</a></li>
              </ul>
            </div>
            <div className="footer-col">
              <h4>Company</h4>
              <ul>
                <li><a>About LUXE</a></li>
                <li><a>Careers</a></li>
                <li><a>Privacy Policy</a></li>
                <li><a>Terms of Service</a></li>
              </ul>
            </div>
          </div>
          <div className="footer-bottom">
            <span>© 2025 LUXE. All rights reserved.</span>
            <span>Made with ♥ for fashion lovers</span>
          </div>
        </footer>
      </div>

      <div className={pageClass('login')}>
        <div className="auth-page">
          <div className="auth-visual">
            <div className="auth-visual-logo">LUXE</div>
            <div className="auth-visual-emoji">🛍️</div>
            <h2>Welcome Back</h2>
            <p>Sign in to access your orders, wishlist, and exclusive member-only deals.</p>
          </div>
          <div className="auth-form-side">
            <div className="auth-form-box">
              <h2>Sign In</h2>
              <p className="sub">Enter your credentials to continue</p>
              <div className="form-group">
                <label>Email Address</label>
                <input type="email" placeholder="you@example.com" id="login-email" />
              </div>
              <div className="form-group">
                <label>Password</label>
                <input type="password" placeholder="Enter your password" id="login-pass" />
              </div>
